CREATE TABLE `attendance` (
  `id` varchar(36) NOT NULL DEFAULT uuid(),
  `employee_id` varchar(36) NOT NULL,
  `client_id` varchar(36) NOT NULL,
  `date` date NOT NULL,
  `check_in_time` time DEFAULT NULL,
  `check_out_time` time DEFAULT NULL,
  `break_start_time` time DEFAULT NULL COMMENT 'Actual break start time during shift',
  `break_end_time` time DEFAULT NULL COMMENT 'Actual break end time during shift',
  `total_hours` decimal(4,2) DEFAULT NULL,
  `overtime_hours` decimal(4,2) DEFAULT 0.00,
  `status` enum('present','absent','late','half_day','on_leave') DEFAULT 'present',
  `work_type` enum('office','remote','hybrid') DEFAULT 'office',
  `notes` text DEFAULT NULL,
  `created_by` varchar(36) DEFAULT NULL,
  `updated_by` varchar(36) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `scheduled_in_time` time DEFAULT NULL,
  `scheduled_out_time` time DEFAULT NULL,
  `arrival_status` enum('on_time','late','absent','voluntary_work','scheduled_off') DEFAULT 'on_time',
  `work_duration` enum('full_day','half_day','short_leave','absent','voluntary_full_day','voluntary_half_day','voluntary_short_work','scheduled_off','insufficient_hours') DEFAULT 'full_day',
  `leave_request_id` varchar(36) DEFAULT NULL,
  `is_weekend` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'Day of week: 1=Sunday, 2=Monday, 3=Tuesday, 4=Wednesday, 5=Thursday, 6=Friday, 7=Saturday',
  `payable_duration` int(11) DEFAULT NULL COMMENT 'Payable duration in seconds (for precision)',
  `pre_shift_overtime_seconds` int(11) DEFAULT 0 COMMENT 'Actual seconds worked before scheduled start time as overtime',
  `post_shift_overtime_seconds` int(11) DEFAULT 0 COMMENT 'Actual seconds worked after scheduled end time as overtime',
  `extra_time_from_payable_duration` int(11) DEFAULT 0 COMMENT 'Accumulated extra seconds worked beyond 8hrs this month (resets per month via row context)',
  `saturday_covering_seconds` int(11) DEFAULT 0 COMMENT 'Running total of seconds contributed toward covering Saturday obligation this month',
  `saturday_covering_is_completed` tinyint(1) DEFAULT 0 COMMENT 'Whether Saturday obligation for this month is fully covered',
  `is_auto_covered` tinyint(1) DEFAULT 0 COMMENT 'Whether this attendance record was auto-created by the saturday covering system'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

